arguments.assetAlertList:
{% set data = [] %}
{% for asset in vars.assetList %}
{% set _ = data.append((asset['@id'] + "?$relationships=true") | fromIRI) %}
{% endfor %}
{{data}}

schema.description:
{% for item in vars.assetList %}
{% set criticality = (item.criticality | fromIRI) %}
<h5><li>{{ item.name }} : {{ (item.level | fromIRI).itemValue }} : {{ (item.zone | fromIRI).itemValue }} : <span style="color:{{criticality.color}}">{{ criticality.itemValue }}</span></li></h5>
{% endfor %}
